import{_ as i,a as l,b as o,c as a}from"./chunks/Connected.KElPUq4_.js";import{_ as t,o as d,c,a3 as s}from"./chunks/framework.DXXx-gl1.js";const _=JSON.parse('{"title":"Kdnet远程桌面","description":"","frontmatter":{},"headers":[],"relativePath":"zh/WindowsDebug/KdNetRDP.md","filePath":"zh/WindowsDebug/KdNetRDP.md","lastUpdated":1761392318000}'),r={name:"zh/WindowsDebug/KdNetRDP.md"};function n(u,e,h,m,b,p){return d(),c("div",null,[...e[0]||(e[0]=[s('<h1 id="kdnet远程桌面" tabindex="-1">Kdnet远程桌面 <a class="header-anchor" href="#kdnet远程桌面" aria-label="Permalink to &quot;Kdnet远程桌面&quot;">​</a></h1><blockquote><p>此方法适用于前期调试，可以通过KdNet连接到待测设备Win下的远程桌面测试触摸、USB等<br> 参考自<a href="https://github.com/WOA-Project/" target="_blank" rel="noreferrer">WOA Project</a>的相关教程和资料</p></blockquote><h2 id="准备" tabindex="-1">准备 <a class="header-anchor" href="#准备" aria-label="Permalink to &quot;准备&quot;">​</a></h2><ul><li>一台刚刚释放完Windows的设备，还未启动过系统</li><li>ESP分区的ESP FLAG必须在Windows释放前已经被正确设置</li><li>手机现在处于大容量模式且连接至电脑</li><li>已经阅读完<a href="/DocumentWebsite/zh/WindowsDebug/SetupKDNET.html">KDNET配置教程</a>且至少完整操作过一次</li><li>下载<a href="/DocumentWebsite/WindowsDebug/KdNetRDP/unattend.xml">unattend.xml</a></li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>无人值守只有在第一次启动时才会生效，请确认你是刚刚释放完成系统并安装完驱动。</p><ul><li>安装系统请参阅<a href="/DocumentWebsite/zh/InstallationGuides/WindowsInstallation.html">Windows安装简述</a></li><li>安装驱动教程请参阅<a href="/DocumentWebsite/zh/InstallationGuides/InstallDrivers.html">驱动安装</a>。</li></ul></div><h2 id="配置无人值守" tabindex="-1">配置无人值守 <a class="header-anchor" href="#配置无人值守" aria-label="Permalink to &quot;配置无人值守&quot;">​</a></h2><ul><li>打开文件资源管理器，找到手机的系统盘。</li><li>进入<code>\\Windows\\Panther\\</code></li><li>将刚才创建的<code>unattend.xml</code>复制到这里 <ul><li>可选：你可以修改<code>unattend.xml</code>中的<code>LocalUser</code>为你想要的用户名</li></ul></li><li>弹出磁盘，手机重启，启动uefi。</li><li>等待进入系统，正常流程是： <ul><li>转圈 -&gt; 准备xxx -&gt; 准备就绪 -&gt; 自动重启</li></ul></li><li>自动重启后，再次启动uefi，正常流程是： <ul><li>转圈 -&gt; 念诗OOBE -&gt; 进桌面，用户为<code>LocalUser</code></li></ul></li><li>注意上两步所有操作都是自动的，你只需要启动两次uefi</li><li>如果在第一次启动时遇到了<code>Windows无法完成安装xxxxx点击确认重启</code>，请检查ESP FLAG是否设置，并重新安装Windows</li></ul><h2 id="windbg连接" tabindex="-1">Windbg连接 <a class="header-anchor" href="#windbg连接" aria-label="Permalink to &quot;Windbg连接&quot;">​</a></h2><ul><li>参考<a href="/DocumentWebsite/zh/WindowsDebug/SetupKDNET.html#设置bcd">此处</a>配置KDNET并连接 <ul><li>如果中途自动<code>break</code>了，可以点击左上角的<code>Go</code>或在命令行输入<code>g</code>然后回车</li></ul></li><li>在手机进入系统后，点击Windbg窗口左上角<code>break</code>按钮，在窗口中间的命令行中输入<code>!process 0 1</code>并回车，等待输出完毕</li><li>随便找一个Process，点击<code>Peb</code>后面的蓝色数据，Windbg会执行命令并输出一大堆内容。 <img src="'+i+'" alt="Process"></li><li>在输出的内容中找到<code>USERDOMAIN</code>， 复制后面的内容，一般为为<code>PHONE-XXXXX</code>或<code>DESKTOP-XXXX</code><img src="'+l+'" alt="UserDomain"></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果点开一个Peb里面没有<code>USERDOMAIN</code>的话， 可以考虑换一个Process的<code>Peb</code></p></div><h2 id="rdp连接" tabindex="-1">RDP连接 <a class="header-anchor" href="#rdp连接" aria-label="Permalink to &quot;RDP连接&quot;">​</a></h2><ul><li>打开Windows自带的RDP工具<code>远程桌面连接</code>， 你可以在开始菜单搜索到， 或者按<code>Win+R</code>在运行窗口输入<code>mstsc</code></li><li>输入刚才复制的<code>USERDOMAIN</code>， 填入计算机一栏中，点击连接 <img src="'+o+'" alt="连接"></li><li>用户名为<code>LocalUser</code>， 或者你在<code>unattend.xml</code>中自定义的用户名。</li><li>没有密码，输入用户名连接即可，如果提示证书不对，点击忽略确认即可。</li><li>如果远程桌面连接窗口成功连接到系统，则一切配置完成，开启你的调试之旅吧！ <img src="'+a+'" alt="连接成功"></li></ul><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://learn.microsoft.com/zh-cn/windows-hardware/manufacture/desktop/update-windows-settings-and-scripts-create-your-own-answer-file-sxs" target="_blank" rel="noreferrer">MSDN: 应答文件</a></li></ul>',14)])])}const f=t(r,[["render",n]]);export{_ as __pageData,f as default};
